def verify_hmac(data: bytes, signature: str) -> bool:
    if not HMAC_SECRET:
        raise ValueError("HMAC_SECRET not configured")
    
    expected_signature = hmac.new(HMAC_SECRET, data, hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected_signature, signature)


def generate_hmac(data: bytes) -> str:
    if not HMAC_SECRET:
        raise ValueError("HMAC_SECRET not configured")
    
    return hmac.new(HMAC_SECRET, data, hashlib.sha256).hexdigest()


